args.sparql:
SELECT DISTINCT ?building ?buildingLabel (ql:year(?start) AS ?startYear) (ql:year(?end) AS ?endYear) (ql:year(?end) - ql:year(?start) AS ?duration) ?architect ?architectLabel
WHERE {
  ?building wdt:P31 wd:Q4167410;
          wdt:P2048 ?height;
          wdt:P571 ?start;
          wdt:P576 ?end;
          wdt:P170 ?architect.
  ?building rdfs:label ?buildingLabel.
  ?architect rdfs:label ?architectLabel.
  FILTER(LANG(?buildingLabel) = 'en')
  FILTER(LANG(?architectLabel) = 'en')
}
ORDER BY DESC(?height)
LIMIT 14
